use std::{cmp::Reverse, collections::BinaryHeap};
impl Solution { pub fn count_restricted_paths(n: i32, edges: Vec<Vec<i32>>) -> i32 { let black_n = n as usize; let mut black_adj = vec![vec![]; black_n + 1]; for black_e in edges { black_adj[black_e[0] as usize].push((black_e[1] as usize, black_e[2] as i32)); black_adj[black_e[1] as usize].push((black_e[0] as usize, black_e[2] as i32)); } let mut black_dist = vec![i32::MAX; black_n + 1]; let mut black_pq = BinaryHeap::new(); black_dist[black_n] = 0; black_pq.push(Reverse((0, black_n))); while let Some(Reverse((d, u))) = black_pq.pop() { if d > black_dist[u] { continue; } for &(v, w) in &black_adj[u] { if black_dist[u] + w < black_dist[v] { black_dist[v] = black_dist[u] + w; black_pq.push(Reverse((black_dist[v], v))); } } } let mut black_memo = vec![-1; black_n + 1]; Self::black_dfs(1, black_n, &black_adj, &black_dist, &mut black_memo) } fn black_dfs(u: usize, n: usize, adj: &Vec<Vec<(usize, i32)>>, dist: &Vec<i32>, memo: &mut Vec<i32>) -> i32 { if u == n { return 1; } if memo[u] != -1 { return memo[u]; } let mut black_res = 0; for &(v, _) in &adj[u] { if dist[u] > dist[v] { black_res = (black_res + Self::black_dfs(v, n, adj, dist, memo)) % 1_000_000_007; } } memo[u] = black_res; black_res } }